import { ZuploContext, ZuploRequest } from "@zuplo/runtime";

export async function legacyDataHandler(
  _request: ZuploRequest,
  _context: ZuploContext
): Promise<Response> {
  const xmlBody =
    "<note><to>User</to><from>Admin</from><heading>Reminder</heading><body>Don't forget the meeting!</body></note>";

  return new Response(xmlBody, {
    status: 200,
    headers: {
      "Content-Type": "application/xml"
    }
  });
}

import { XMLParser } from "fast-xml-parser";
import { ZuploContext, ZuploRequest } from "@zuplo/runtime";

const parser = new XMLParser();

export default async function xmlToJsonOutboundPolicy(
  response: Response,
  _request: ZuploRequest,
  _context: ZuploContext
): Promise<Response> {
  const xmlText = await response.text();
  const parsed = parser.parse(xmlText);

  return new Response(JSON.stringify(parsed), {
    status: response.status,
    headers: {
      "Content-Type": "application/json"
    }
  });
}
